	// Perform scan
	progress := make(chan uint32, 100)
	scanner.Scan(ctx, *lib, true, progress)
	close(progress)

	// Get scanned media files
	mfs, _ := ds.MediaFile(ctx).GetAll()
	if len(mfs) == 0 {
		t.Logf("No files scanned")
		return
	}

	// Check that album and artist IDs are set
	mf := mfs[0]
	if mf.AlbumID == "" {
		t.Error("Album ID should be assigned during scan")
	}

	if mf.ArtistID == "" {
		t.Error("Artist ID should be assigned during scan")
	}

	if mf.AlbumArtistID == "" {
		t.Error("Album Artist ID should be assigned during scan")
	}

	// Verify album exists in store
	albums, _ := ds.Album(ctx).GetAll()
	if len(albums) > 0 {
		// At least one album should exist
		if albums[0].ID == "" {
			t.Error("Album ID should not be empty")
		}
	}
}

// TestScannerProgressTracking tests that progress is reported during scan
func TestScannerProgressTracking(t *testing.T) {
	tests.Init(t, true)
	ctx := context.Background()

	musicDir, lib, cleanup := setupTestLibrary(t)
	defer cleanup()

	ds := NewIntegrationDataStore()
	ds.libraryRepo.(*MockLibraryRepo).libraries = map[int]*model.Library{
		lib.ID: lib,
	}

	scanner := NewTagScanner(ds, &MockPlaylists{}, &MockCacheWarmer{})

	// Perform scan with progress tracking
	progress := make(chan uint32, 100)
	go func() {
		scanner.Scan(ctx, *lib, true, progress)
		close(progress)
	}()

	// Read progress updates
	progressReceived := false
	for range progress {
		progressReceived = true
	}

	// Progress may or may not be reported depending on file structure
	t.Logf("Progress tracking completed. Progress received: %v", progressReceived)
}

