// TestScannerBasicScan tests that the scanner can scan a directory and create media files
func TestScannerBasicScan(t *testing.T) {
	tests.Init(t, true)
	ctx := context.Background()

	musicDir, lib, cleanup := setupTestLibrary(t)
	defer cleanup()

	ds := NewIntegrationDataStore()
	ds.libraryRepo.(*MockLibraryRepo).libraries = map[int]*model.Library{
		lib.ID: lib,
	}

	// Create scanner
	scanner := NewTagScanner(ds, &MockPlaylists{}, &MockCacheWarmer{})

	// Perform scan
	progress := make(chan uint32, 100)
	count, err := scanner.Scan(ctx, *lib, true, progress)
	close(progress)

	// Verify
	if count < 0 {
		t.Errorf("Expected non-negative count, got %d", count)
	}

	// Check that media files were added to the store
	mfs, _ := ds.MediaFile(ctx).GetAll()
	if len(mfs) == 0 {
		t.Logf("No files scanned (expected if test fixtures not available)")
		return
	}

	// Verify basic structure of media file
	if len(mfs) > 0 {
		mf := mfs[0]
		if mf.Path == "" {
			t.Error("MediaFile path should not be empty")
		}
	}
}

// TestScannerMetadataExtraction tests that metadata is correctly extracted from audio files
func TestScannerMetadataExtraction(t *testing.T) {
